fn solve(n: i64) -> bool {
    if n == 0 {
        return false;
    }

    let digits: Vec<char> = n.to_string().chars().collect();
    let sum: i64 = digits.iter().map(|c| c.to_digit(10).unwrap() as i64).sum();
    let product: i64 = digits.iter().map(|c| c.to_digit(10).unwrap() as i64).product();

    (sum + product) % n == 0
}
